import React, { useState } from 'react';
import axios from 'axios';
import { Link, useNavigate } from 'react-router-dom';

function AddTask(){
    const [values, setValues] = useState({
        description: '',
        priority: '',
        status: '',
        target_date: '',
        user_id:''
    })

    function handleSubmit(e){
        e.preventDefault();
        axios.post('/', values)
        .then((res)=> {
            const navigate = useNavigate();
            navigate('/');
            console.log(res);
        })
        .catch((err)=>console.log(err))
    }
    return(
        <div>
            <div className="row">
                <h3>Add Task</h3>
                <div>
                    <Link to='/' class='btn btn-success'>Home</Link>
                </div>
                <form onSubmit={handleSubmit}>
                    <div>
                        <label htmlFor="description">Description</label>
                        <input type='text' name='description' onChange={(e) => setValues({...values, description: e.target.value})}/>
                    </div>
                    <div>
                        <label htmlFor="priority">Priority</label>
                        <select id='priority' name='priority' onChange={(e) => setValues({...values, priority: e.target.value})}>
                            <option value="High">High</option>
                            <option value="Medium">Medium</option>
                            <option value="Low">Low</option>
                        </select>
                    </div>
                    <div>
                        <label htmlFor="status">Status</label>
                        <select id='status' name='status' onChange={(e) => setValues({...values, status: e.target.value})}>
                            <option value="scheduled">Scheduled</option>
                            <option value="inProgress">In progress</option>
                            <option value="completed">Completed</option>
                        </select>
                    </div>
                    <div>
                        <lable htmlFor="target_date">Target Date</lable>
                        <input type='date' name='target_date' value= {target_date} onChange={(e) => setValues({...values, target_date: e.target.value})}/>
                    </div>
                </form>
            </div>
        </div>
    )
}

export default AddTask;
